import pytest
from typing import Callable, Any

def group_by(items: list, key_fn: Callable[[Any], Any]) -> dict:
    result = {}
    for item in items:
        k = key_fn(item)
        result.setdefault(k, []).append(item)
    return result

class TestGroupBy:
    def test_happy_path_with_simple_key_function(self):
        """Test basic grouping with a simple key function"""
        items = [{'name': 'Alice', 'age': 25}, {'name': 'Bob', 'age': 30}]
        key_fn = lambda x: x['name']

        result = group_by(items, key_fn)
        assert result == {
            'Alice': [{'name': 'Alice', 'age': 25}],
            'Bob': [{'name': 'Bob', 'age': 30}]
        }

