        key_fn = lambda x: (x['group'], x['score'] > 90)

        result = group_by(items, key_fn)
        assert result == {
            ('A', False): [
                {'name': 'Alice', 'group': 'A', 'score': 90},
                {'name': 'Bob', 'group': 'A', 'score': 85}
            ],
            ('B', True): [
                {'name': 'Charlie', 'group': 'B', 'score': 95}
            ]
        }

    def test_empty_list(self):
        """Test behavior with empty input list"""
