        key_fn = lambda x: x['name']

        result = group_by(items, key_fn)
        assert result == {
            'Alice': [{'name': 'Alice', 'age': 25}]
        }

    def test_duplicate_keys(self):
        """Test behavior with duplicate keys (should maintain order)"""
        items = [
            {'name': 'Alice', 'age': 25},
            {'name': 'Bob', 'age': 30},
            {'name': 'Alice', 'age': 35},
